        "rawQuery": true,
        "rawSql": "SELECT $__timeGroupAlias(fd.time,$__interval), fd.flow AS \"Caudal\", fm.name\nFROM wua_flowdata fd\nLEFT JOIN wua_flowmeter fm ON fd.flowmeter_id = fm.id\nWHERE fm.name = '${flowmeter}'\n  AND $__timeFilter(fd.time)\nGROUP BY fd.time, fd.flow, fm.name\nORDER BY fd.time\n",
